const b = $('Webhook').item.json.body;
const inputs = b.inputs || {};
const now = new Date(b.timestamp || Date.now());
const dateVi = now.toLocaleString('vi-VN', { timeZone: 'Asia/Ho_Chi_Minh', year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });
const pct = v => (v * 100).toFixed(1);
const sheetUrl = 'https://docs.google.com/spreadsheets/d/1ASE9CUCseFaU2cr99PrSVEfxWbxUkNGZ1xQhox5AKLM';
const risks = [];
if ((inputs.Delay_from_due_date||0)>15) risks.push('Trả trễ '+inputs.Delay_from_due_date+' ngày');
if ((inputs.Num_of_Delayed_Payment||0)>10) risks.push(inputs.Num_of_Delayed_Payment+' lần trễ');
if ((inputs.Debt_to_Income_Annual||0)>0.5) risks.push('DTI '+((inputs.Debt_to_Income_Annual||0)*100).toFixed(0)+'%');
if ((inputs.Credit_Utilization_Ratio||0)>70) risks.push('Utilization '+(inputs.Credit_Utilization_Ratio||0).toFixed(0)+'%');
if (inputs.Credit_Mix==='Bad') risks.push('Credit Mix Bad');
if (inputs.Has_Payday_Loan) risks.push('Có Payday Loan');
const subject = '🚨 CẢNH BÁO POOR: '+(b.customer_name||'Ẩn danh')+' — P(Poor)='+pct(b.proba.Poor)+'%';
const html = '<div style="font-family:Arial;max-width:600px;border:2px solid #e74c3c;border-radius:8px;overflow:hidden;"><div style="background:#e74c3c;padding:16px;color:white;"><h2 style="margin:0;">🚨 Hồ sơ rủi ro cao — POOR</h2><p style="margin:4px 0 0;opacity:0.85;">'+dateVi+'</p></div><div style="padding:20px;"><table style="width:100%;border-collapse:collapse;"><tr><td style="padding:8px;color:#555;">Khách hàng</td><td style="padding:8px;font-weight:bold;">'+(b.customer_name||'Ẩn danh')+'</td></tr><tr style="background:#fafafa;"><td style="padding:8px;color:#555;">Email</td><td style="padding:8px;">'+(b.customer_email||'—')+'</td></tr><tr><td style="padding:8px;color:#555;">P(Poor)</td><td style="padding:8px;font-weight:bold;color:#e74c3c;font-size:18px;">'+pct(b.proba.Poor)+'%</td></tr><tr style="background:#fafafa;"><td style="padding:8px;color:#555;">P(Good)</td><td style="padding:8px;">'+pct(b.proba.Good)+'%</td></tr></table>'+(risks.length?'<div style="margin-top:12px;background:#fff5f5;border-left:3px solid #e74c3c;padding:12px;"><b style="color:#c0392b;">Yếu tố rủi ro:</b><ul style="margin:8px 0;padding-left:20px;">'+risks.map(r=>'<li>'+r+'</li>').join('')+'</ul></div>':'')+'<div style="text-align:center;margin-top:16px;"><a href="'+sheetUrl+'" style="background:#e74c3c;color:white;padding:10px 24px;border-radius:6px;text-decoration:none;font-weight:bold;">Xem trong Sheets →</a></div></div></div>';
return { json: { subject, alertHTML: html } };

const rows = $input.all().map(r => r.json);
const b = $('Webhook').item.json.body;
const currentEmail = (b.customer_email||'').toLowerCase().trim();
const currentTs = b.timestamp;
const matched = rows.filter(r => {
  const e = (r['Email']||'').toLowerCase().trim();
  return e === currentEmail && r['Thời gian'] !== currentTs;
});
matched.sort((a,b2) => new Date(b2['Thời gian']) - new Date(a['Thời gian']));
const isNew = matched.length === 0;
const visitCount = matched.length + 1;
const prev = matched[0] || null;
let previousData = null;
if (prev) {
  previousData = {
    timestamp: prev['Thời gian'],
    predicted_class: prev['Nhóm dự đoán'],
    proba: {
      Poor: parseFloat((prev['Xác suất Poor']||'0').toString().replace(',','.')) || 0,
      Standard: parseFloat((prev['Xác suất Standard']||'0').toString().replace(',','.')) || 0,
      Good: parseFloat((prev['Xác suất Good']||'0').toString().replace(',','.')) || 0
    }
  };
}
const improving = previousData ? (b.proba.Good - previousData.proba.Good) > 0.05 : false;
const stagnant = previousData ? (b.predicted_class==='Poor' && previousData.predicted_class==='Poor' && !improving) : false;
return [{ json: { isNew, visitCount, previousData, improving, stagnant } }];

const b = $('Webhook').item.json.body;
const hist = $('KB1: Compare History').item.json;
const inputs = b.inputs || {};
const pct = v => (v * 100).toFixed(1);
const now = new Date(b.timestamp || Date.now());
const dateVi = now.toLocaleString('vi-VN', { timeZone: 'Asia/Ho_Chi_Minh', year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });
const cls = b.predicted_class || 'Unknown';
const clsViMap = { Poor: 'Rủi ro cao', Standard: 'Trung bình', Good: 'Tốt' };
const clsVi = clsViMap[cls] || cls;
const clsColorMap = { Poor: '#e74c3c', Standard: '#f39c12', Good: '#27ae60' };
const clsColor = clsColorMap[cls] || '#888';
const visitCount = hist.visitCount || 1;
const isNew = hist.isNew !== false;
const improving = !!hist.improving;
const stagnant = !!hist.stagnant;
const prev = hist.previousData;
const greeting = isNew ? 'Đây là lần đầu tiên bạn sử dụng hệ thống của chúng tôi.' : 'Đây là lần thứ <b>'+visitCount+'</b> bạn sử dụng hệ thống. Cảm ơn bạn đã quay lại!';
let bannerHTML = '';
if (!isNew && prev) {
  const clsOrder = { Poor: 0, Standard: 1, Good: 2 };
  if ((clsOrder[cls]||0) > (clsOrder[prev.predicted_class]||0)) {
    bannerHTML = '<div style="background:#d4efdf;border-left:4px solid #27ae60;padding:12px;margin:12px 0;">🎉 <b>Chúc mừng!</b> Hạng tín dụng nâng từ '+prev.predicted_class+' lên '+cls+'!</div>';
  } else if ((clsOrder[cls]||0) < (clsOrder[prev.predicted_class]||0)) {
    bannerHTML = '<div style="background:#fde8e8;border-left:4px solid #e74c3c;padding:12px;margin:12px 0;">⚠️ <b>Lưu ý:</b> Hạng giảm từ '+prev.predicted_class+' xuống '+cls+'.</div>';
  } else if (improving) {
    bannerHTML = '<div style="background:#eaf4fb;border-left:4px solid #3498db;padding:12px;margin:12px 0;">📈 P(Good) tăng >5% so với lần trước.</div>';
  }
}
let compareHTML = '';
if (!isNew && prev) {
  const dP = (b.proba.Poor - prev.proba.Poor)*100, dS = (b.proba.Standard - prev.proba.Standard)*100, dG = (b.proba.Good - prev.proba.Good)*100;
  const ar = v => v>0.05?'<span style="color:#e74c3c">▲'+v.toFixed(1)+'%</span>':v<-0.05?'<span style="color:#27ae60">▼'+Math.abs(v).toFixed(1)+'%</span>':'<span style="color:#888">—</span>';
  compareHTML = '<h3>So sánh lần trước ('+new Date(prev.timestamp).toLocaleDateString('vi-VN')+')</h3><table style="width:100%;border-collapse:collapse;"><tr style="background:#f0f0f0;"><th style="padding:6px;text-align:left;">Nhóm</th><th style="padding:6px;text-align:right;">Trước</th><th style="padding:6px;text-align:right;">Nay</th><th style="padding:6px;text-align:right;">Δ</th></tr><tr><td style="padding:6px;color:#e74c3c;">Poor</td><td style="padding:6px;text-align:right;">'+pct(prev.proba.Poor)+'%</td><td style="padding:6px;text-align:right;">'+pct(b.proba.Poor)+'%</td><td style="padding:6px;text-align:right;">'+ar(dP)+'</td></tr><tr style="background:#fafafa;"><td style="padding:6px;color:#f39c12;">Standard</td><td style="padding:6px;text-align:right;">'+pct(prev.proba.Standard)+'%</td><td style="padding:6px;text-align:right;">'+pct(b.proba.Standard)+'%</td><td style="padding:6px;text-align:right;">'+ar(dS)+'</td></tr><tr><td style="padding:6px;color:#27ae60;">Good</td><td style="padding:6px;text-align:right;">'+pct(prev.proba.Good)+'%</td><td style="padding:6px;text-align:right;">'+pct(b.proba.Good)+'%</td><td style="padding:6px;text-align:right;">'+ar(dG)+'</td></tr></table>';
}
let adviceHTML = '';
if (cls==='Poor') {
  const issues = [];
  if ((inputs.Delay_from_due_date||0)>15) issues.push('Thanh toán đang trễ '+inputs.Delay_from_due_date+' ngày — cần thanh toán ngay');
  if ((inputs.Num_of_Delayed_Payment||0)>10) issues.push('Có '+inputs.Num_of_Delayed_Payment+' lần trễ hạn — thiết lập nhắc nhở tự động');
  if ((inputs.Debt_to_Income_Annual||0)>0.5) issues.push('Tỷ lệ nợ/thu nhập '+((inputs.Debt_to_Income_Annual||0)*100).toFixed(0)+'% — cần giảm dư nợ');
  if ((inputs.Credit_Utilization_Ratio||0)>70) issues.push('Credit Utilization '+(inputs.Credit_Utilization_Ratio||0).toFixed(0)+'% — giảm xuống dưới 30%');
  if (inputs.Credit_Mix==='Bad') issues.push('Credit Mix xấu — đa dạng hóa tín dụng');
  if (inputs.Has_Payday_Loan) issues.push('Có Payday Loan — ưu tiên trả trước');
  if (stagnant) {
    adviceHTML = '<div style="background:#fff3cd;border-left:4px solid #f39c12;padding:12px;margin:12px 0;"><b>⚠️ Chưa có cải thiện so với lần trước.</b> Hãy tập trung vào <b>1 việc</b> trước: '+(issues[0]||'thanh toán đúng hạn')+'</div>';
  } else if (isNew) {
    adviceHTML = '<h3 style="color:#e74c3c;">🔴 Vấn đề khẩn cần xử lý</h3>'+(issues.length?'<ul>'+issues.map(i=>'<li>'+i+'</li>').join('')+'</ul>':'')+'<p><b>Lộ trình cải thiện:</b></p><ul><li><b>1-3 tháng:</b> Thanh toán đúng hạn 100%, giảm utilization</li><li><b>3-6 tháng:</b> Giảm dư nợ, hạn chế vay mới</li><li><b>6-12 tháng:</b> Xây dựng lịch sử tín dụng sạch</li></ul>';
  } else if (improving) {
    adviceHTML = '<div style="background:#d4efdf;padding:12px;border-radius:4px;">💪 Bạn đang tiến bộ tốt! Tiếp tục duy trì các thói quen tốt. '+( issues.length?'Vẫn còn: <i>'+issues[0]+'</i>':'')+'</div>';
  } else {
    adviceHTML = '<ul>'+issues.map(i=>'<li>'+i+'</li>').join('')+'</ul>';
  }
} else if (cls==='Standard') {
  adviceHTML = '<h3 style="color:#f39c12;">📊 Rào cản để đạt hạng Good</h3><ul><li>Giữ Credit Utilization dưới 30%</li><li>Không trễ hạn bất kỳ khoản nào</li><li>Duy trì DTI dưới 40%</li><li>Đa dạng hóa danh mục tín dụng</li></ul>';
} else if (cls==='Good') {
  adviceHTML = '<h3 style="color:#27ae60;">✅ Tín dụng tốt — Duy trì và phát triển</h3><ul><li>Tiếp tục thanh toán đúng hạn</li><li>Giữ utilization dưới 30%</li><li>Bạn có thể xem xét: thẻ tín dụng ưu đãi, vay mua nhà lãi suất thấp</li></ul>';
}
const subject = '[Lần '+visitCount+'] Kết quả tín dụng: '+clsVi+' ('+cls+')';
const emailHTML = '<!DOCTYPE html><html><body style="margin:0;padding:0;background:#f4f6f9;"><div style="font-family:Arial,sans-serif;max-width:640px;margin:20px auto;background:white;border-radius:8px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.1);"><div style="background:'+clsColor+';padding:20px;color:white;"><h2 style="margin:0;">Kết quả Đánh giá Tín dụng</h2><p style="margin:4px 0 0;opacity:0.85;">'+dateVi+'</p></div><div style="padding:24px;"><p>Xin chào <b>'+(b.customer_name||'bạn')+'</b>,</p><p>'+greeting+'</p>'+bannerHTML+'<div style="background:#f8f9fa;border-radius:8px;padding:16px;text-align:center;margin:16px 0;"><div style="font-size:14px;color:#666;">Phân loại tín dụng</div><div style="font-size:32px;font-weight:bold;color:'+clsColor+';">'+clsVi+'</div><div style="font-size:13px;color:#888;">('+cls+')</div></div><h3 style="border-bottom:1px solid #eee;padding-bottom:6px;">Xác suất chi tiết</h3><table style="width:100%;border-collapse:collapse;"><tr style="background:#f8f9fa;"><td style="padding:8px;color:#e74c3c;">🔴 Poor</td><td style="padding:8px;text-align:right;font-weight:bold;">'+pct(b.proba.Poor)+'%</td></tr><tr><td style="padding:8px;color:#f39c12;">🟡 Standard</td><td style="padding:8px;text-align:right;font-weight:bold;">'+pct(b.proba.Standard)+'%</td></tr><tr style="background:#f8f9fa;"><td style="padding:8px;color:#27ae60;">🟢 Good</td><td style="padding:8px;text-align:right;font-weight:bold;">'+pct(b.proba.Good)+'%</td></tr></table>'+compareHTML+adviceHTML+'<hr style="margin:20px 0;border:none;border-top:1px solid #eee;"><p style="color:#999;font-size:12px;text-align:center;">Email tự động — AI Credit Classification — Đồ án học tập</p></div></div></body></html>';
return [{ json: { subject, emailHTML } }];

const rows = $input.all().map(r => r.json);
const now = new Date();
const sevenDaysAgo = new Date(now.getTime() - 7*24*60*60*1000);
const recent = rows.filter(r => {
  const ts = new Date(r['Thời gian']);
  return !isNaN(ts) && ts >= sevenDaysAgo;
});
const total = recent.length;
const poor = recent.filter(r => r['Nhóm dự đoán']==='Poor').length;
const standard = recent.filter(r => r['Nhóm dự đoán']==='Standard').length;
const good = recent.filter(r => r['Nhóm dự đoán']==='Good').length;
const withEmail = recent.filter(r => r['Email'] && r['Email'].toString().trim()!=='').length;
const withoutEmail = total - withEmail;
const emailMap = {};
recent.forEach(r => {
  const em = (r['Email']||'').toString().toLowerCase().trim();
  if (em) emailMap[em] = (emailMap[em]||0) + 1;
});
const uniqueEmails = Object.keys(emailMap).length;
const returnCustomers = Object.values(emailMap).filter(v => v >= 2).length;
const returnRate = uniqueEmails > 0 ? ((returnCustomers / uniqueEmails)*100).toFixed(1) : '0.0';
const avgPerDay = (total / 7).toFixed(1);
const dayMap = {};
recent.forEach(r => {
  const ts = new Date(r['Thời gian']);
  if (!isNaN(ts)) {
    const day = ts.toLocaleDateString('vi-VN');
    dayMap[day] = (dayMap[day]||0) + 1;
  }
});
let peakDay = '—', peakCount = 0;
Object.entries(dayMap).forEach(([d, c]) => { if (c > peakCount) { peakCount = c; peakDay = d; } });
const topEmails = Object.entries(emailMap).sort((a,b) => b[1]-a[1]).slice(0,5);
const weekStr = sevenDaysAgo.toLocaleDateString('vi-VN')+' - '+now.toLocaleDateString('vi-VN');
const pctOf = (n,d) => d>0 ? (n/d*100).toFixed(1)+'%' : '0%';
const reportHTML = '<!DOCTYPE html><html><body style="font-family:Arial;max-width:700px;margin:20px auto;background:#f4f6f9;"><div style="background:white;border-radius:8px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.1);"><div style="background:#2c3e50;padding:20px;color:white;"><h2 style="margin:0;">📊 Báo cáo tuần — AI Credit Scoring</h2><p style="margin:4px 0 0;opacity:0.8;">'+weekStr+'</p></div><div style="padding:24px;"><h3 style="color:#2c3e50;">Tổng quan KPI</h3><table style="width:100%;border-collapse:collapse;"><tr style="background:#2c3e50;color:white;"><th style="padding:10px;text-align:left;">Chỉ số</th><th style="padding:10px;text-align:right;">Giá trị</th></tr><tr><td style="padding:8px;">Tổng lượt đánh giá</td><td style="padding:8px;text-align:right;font-weight:bold;">'+total+'</td></tr><tr style="background:#f8f9fa;"><td style="padding:8px;">Trung bình lượt/ngày</td><td style="padding:8px;text-align:right;">'+avgPerDay+'</td></tr><tr><td style="padding:8px;">Ngày cao điểm</td><td style="padding:8px;text-align:right;">'+peakDay+' ('+peakCount+' lượt)</td></tr></table><h3 style="color:#2c3e50;margin-top:20px;">Phân bố nhóm tín dụng</h3><table style="width:100%;border-collapse:collapse;"><tr style="background:#f0f0f0;"><th style="padding:8px;text-align:left;">Nhóm</th><th style="padding:8px;text-align:right;">Số lượng</th><th style="padding:8px;text-align:right;">Tỷ lệ</th></tr><tr><td style="padding:8px;color:#e74c3c;">🔴 Poor</td><td style="padding:8px;text-align:right;">'+poor+'</td><td style="padding:8px;text-align:right;">'+pctOf(poor,total)+'</td></tr><tr style="background:#f8f9fa;"><td style="padding:8px;color:#f39c12;">🟡 Standard</td><td style="padding:8px;text-align:right;">'+standard+'</td><td style="padding:8px;text-align:right;">'+pctOf(standard,total)+'</td></tr><tr><td style="padding:8px;color:#27ae60;">🟢 Good</td><td style="padding:8px;text-align:right;">'+good+'</td><td style="padding:8px;text-align:right;">'+pctOf(good,total)+'</td></tr></table><h3 style="color:#2c3e50;margin-top:20px;">Engagement khách hàng</h3><table style="width:100%;border-collapse:collapse;"><tr style="background:#f0f0f0;"><th style="padding:8px;text-align:left;">Chỉ số</th><th style="padding:8px;text-align:right;">Giá trị</th></tr><tr><td style="padding:8px;">Có email</td><td style="padding:8px;text-align:right;">'+withEmail+'</td></tr><tr style="background:#f8f9fa;"><td style="padding:8px;">Không có email</td><td style="padding:8px;text-align:right;">'+withoutEmail+'</td></tr><tr><td style="padding:8px;">Email duy nhất</td><td style="padding:8px;text-align:right;">'+uniqueEmails+'</td></tr><tr style="background:#f8f9fa;"><td style="padding:8px;">Khách quay lại (≥2 lượt)</td><td style="padding:8px;text-align:right;">'+returnCustomers+' ('+returnRate+'%)</td></tr></table>'+(topEmails.length?'<h3 style="color:#2c3e50;margin-top:20px;">Top 5 khách hàng</h3><table style="width:100%;border-collapse:collapse;"><tr style="background:#f0f0f0;"><th style="padding:8px;text-align:left;">Email</th><th style="padding:8px;text-align:right;">Số lượt</th></tr>'+topEmails.map((e,i)=>'<tr'+(i%2?' style="background:#f8f9fa;"':'')+'><td style="padding:8px;">'+e[0]+'</td><td style="padding:8px;text-align:right;">'+e[1]+'</td></tr>').join('')+'</table>':'')+'<hr style="margin:20px 0;"><p style="color:#999;font-size:12px;text-align:center;">Báo cáo tự động — AI Credit Classification — Đồ án học tập</p></div></div></body></html>';
const subject = '[Báo cáo tuần] AI Credit Scoring — '+weekStr;
return [{ json: { subject, reportHTML, total, poor, standard, good, withEmail, returnCustomers, returnRate, avgPerDay, weekStr } }];
